<script setup lang="ts">import { computed,ref } from 'vue';import { useRouter } from 'vue-router';import type { Agent,Room,RunSnapshot } from '../domain/types';import RoomBuilding from './RoomBuilding.vue';import CentralHall from './CentralHall.vue';import { world } from '../store/world';const router=useRouter();const p=defineProps<{teamId:number;rooms:readonly Room[];agents:readonly Agent[];run:RunSnapshot}>();const group=computed(()=>p.rooms.filter(r=>r.type==='group'));const runtime=(id:number)=>p.run.roomRuns[id]||{roomId:id,status:'waiting',progress:0,currentAgentId:null,currentNpcStatus:'idle',activityLabel:'静候差遣',completedTasks:0,totalTasks:0,lastActivityAt:null};const rootRoomId=computed(()=>p.run.rootRoomId??null);const rootRoom=computed(()=>rootRoomId.value==null?undefined:group.value.find(r=>r.id===rootRoomId.value));const sideRooms=computed(()=>group.value.filter(r=>r.id!==rootRoom.value?.id));const starting=ref(false);
async function startNewSession(){if(!rootRoom.value||starting.value)return;starting.value=true;try{await world.startNewSession(rootRoom.value.id);router.push({name:'room',params:{teamId:p.teamId,roomId:rootRoom.value.id},query:{new:'1'}});}catch(e){console.error('发起新讨论失败',e);}finally{starting.value=false;}}
</script>
<template><div class="courtyard-wrap"><div class="mountains" aria-hidden="true"><i></i><i></i><i></i></div><div class="courtyard" aria-label="团队院落鸟瞰图"><div class="path-stone" aria-hidden="true"></div><div v-for="(room,index) in sideRooms" :key="room.id" class="room-slot" :class="`slot-${index%8}`"><RoomBuilding :room="room" :runtime="runtime(room.id)" :agents="agents.filter(a=>room.agentIds.includes(a.id))"/></div><div class="central-slot"><CentralHall :run="run" :rooms="group" :agents="agents"/><div class="hall-actions"><RouterLink v-if="rootRoom" class="enter-hall" :to="{name:'room',params:{teamId,roomId:rootRoom.id}}">入殿问策</RouterLink><button v-if="rootRoom" class="new-session-btn" :disabled="starting" @click="startNewSession">{{starting?'正在准备…':'发起新讨论'}}</button></div></div></div></div></template>
